 25→public class MaxLineLengthRule :
 26→    StandardRule(
 27→        id = "max-line-length",
 28→        visitorModifiers = setOf(
 29→            VisitorModifier.RunAfterRule(
 30→                // This rule should run after all other rules. Each time a rule visitor is modified with
 31→                // RunAsLateAsPossible, it needs to be checked that this rule still runs after that new rule or that it
 32→                // won't be affected by that rule.
 33→                ruleId = TRAILING_COMMA_ON_CALL_SITE_RULE_ID,
 34→                mode = REGARDLESS_WHETHER_RUN_AFTER_RULE_IS_LOADED_OR_DISABLED,
 35→            ),
 36→            VisitorModifier.RunAfterRule(
 37→                // This rule should run after all other rules. Each time a rule visitor is modified with
 38→                // RunAsLateAsPossible, it needs to be checked that this rule still runs after that new rule or that it
 39→                // won't be affected by that rule.
 40→                ruleId = TRAILING_COMMA_ON_DECLARATION_SITE_RULE_ID,
 41→                mode = REGARDLESS_WHETHER_RUN_AFTER_RULE_IS_LOADED_OR_DISABLED,
 42→            ),
 43→            VisitorModifier.RunAsLateAsPossible,
 44→        ),
 45→        usesEditorConfigProperties = setOf(
 46→            MAX_LINE_LENGTH_PROPERTY,
 47→            IGNORE_BACKTICKED_IDENTIFIER_PROPERTY,
 48→        ),
 49→    ) {
 50→    private var maxLineLength: Int = MAX_LINE_LENGTH_PROPERTY.defaultValue
 51→    private var rangeTree = RangeTree()
 52→    private var ignoreBackTickedIdentifier = IGNORE_BACKTICKED_IDENTIFIER_PROPERTY.defaultValue
 53→
 54→    override fun beforeFirstNode(editorConfig: EditorConfig) {
 55→        ignoreBackTickedIdentifier = editorConfig[IGNORE_BACKTICKED_IDENTIFIER_PROPERTY]
 56→        maxLineLength = editorConfig[MAX_LINE_LENGTH_PROPERTY]
 57→        if (maxLineLength == MAX_LINE_LENGTH_PROPERTY_OFF) {
 58→            stopTraversalOfAST()
 59→        }
 60→    }
 61→
 62→    override fun beforeVisitChildNodes(
 63→        node: ASTNode,
 64→        autoCorrect: Boolean,
 65→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
 66→    ) {
 67→        if (node.isRoot()) {
 68→            val errorOffset = arrayListOf<Int>()
 69→            node
 70→                .getElementsPerLine()
 71→                .filter { it.lineLength(ignoreBackTickedIdentifier) > maxLineLength }
 72→                .forEach { parsedLine ->
 73→                    val el = parsedLine.elements.last()
 74→                    if (!el.isPartOf(KDoc::class) && !el.isPartOfRawMultiLineString()) {
 75→                        if (!el.isPartOf(PsiComment::class)) {
 76→                            if (!el.isPartOf(KtPackageDirective::class) && !el.isPartOf(KtImportDirective::class)) {
 77→                                // fixme:
 78→                                // normally we would emit here but due to API limitations we need to hold off until
 79→                                // node spanning the same offset is 'visit'ed
 80→                                // (for ktlint-disable directive to have effect (when applied))
 81→                                // this will be rectified in the upcoming release(s)
 82→                                errorOffset.add(parsedLine.offset)
 83→                            }
 84→                        } else {
 85→                            // Allow ktlint-disable comments to exceed max line length
 86→                            if (!el.text.startsWith("// ktlint-disable")) {
 87→                                // if comment is the only thing on the line - fine, otherwise emit an error
 88→                                val prevLeaf = el.prevCodeSibling()
 89→                                if (prevLeaf != null && prevLeaf.startOffset >= parsedLine.offset) {
 90→                                    // fixme:
 91→                                    // normally we would emit here but due to API limitations we need to hold off until
 92→                                    // node spanning the same offset is 'visit'ed
 93→                                    // (for ktlint-disable directive to have effect (when applied))
 94→                                    // this will be rectified in the upcoming release(s)
 95→                                    errorOffset.add(parsedLine.offset)
 96→                                }
 97→                            }
 98→                        }
 99→                    }
100→                }
101→            rangeTree = RangeTree(errorOffset)
102→        } else if (!rangeTree.isEmpty() && node.psi is LeafPsiElement) {
103→            rangeTree
104→                .query(node.startOffset, node.startOffset + node.textLength)
105→                .forEach { offset ->
106→                    emit(offset, "Exceeded max line length ($maxLineLength)", false)
107→                }
108→        }
109→    }
110→
111→    private fun ASTNode.isPartOfRawMultiLineString() =
112→        parent(ElementType.STRING_TEMPLATE, strict = false)
113→            ?.let { it.firstChildNode.text == "\"\"\"" && it.textContains('\n') } == true
114→
115→    public companion object {
116→        public val IGNORE_BACKTICKED_IDENTIFIER_PROPERTY: EditorConfigProperty<Boolean> =
117→            EditorConfigProperty(
118→                type = PropertyType.LowerCasingPropertyType(
119→                    "ktlint_ignore_back_ticked_identifier",
120→                    "Defines whether the backticked identifier (``) should be ignored",
121→                    PropertyType.PropertyValueParser.BOOLEAN_VALUE_PARSER,
122→                    setOf(true.toString(), false.toString()),
123→                ),
124→                defaultValue = false,
125→            )
126→    }
127→}
