 16→public fun ASTNode.nextLeaf(
 17→    includeEmpty: Boolean = false,
 18→    skipSubtree: Boolean = false,
 19→): ASTNode? {
 20→    var n = if (skipSubtree) this.lastChildLeafOrSelf().nextLeafAny() else this.nextLeafAny()
 21→    if (!includeEmpty) {
 22→        while (n != null && n.textLength == 0) {
 23→            n = n.nextLeafAny()
 24→        }
 25→    }
 26→    return n
 27→}
