281→public val ASTNode.column: Int
282→    get() {
283→        var leaf = this.prevLeaf()
284→        var offsetToTheLeft = 0
285→        while (leaf != null) {
286→            if ((leaf.elementType == WHITE_SPACE || leaf.elementType == REGULAR_STRING_PART) && leaf.textContains('\n')) {
287→                offsetToTheLeft += leaf.textLength - 1 - leaf.text.lastIndexOf('\n')
288→                break
289→            }
290→            offsetToTheLeft += leaf.textLength
291→            leaf = leaf.prevLeaf()
292→        }
293→        return offsetToTheLeft + 1
294→    }
