import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import com.pinterest.ktlint.test.LintViolation
import org.junit.jupiter.api.Test

class FunctionReturnTypeSpacingMaxLineLengthTest {
    private val functionReturnTypeSpacingRuleAssertThat = assertThatRule { FunctionReturnTypeSpacingRule() }

    @Test
    fun `Given a function with return type on next line that would exceed max line length when put on same line then do not reformat`() {
        val code =
            """
            fun thisIsAVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryLongFunction():
                AndAlsoALongReturnType {
                return AndAlsoALongReturnType()
            }
            """.trimIndent()
        // max_line_length is 120 by default in tests
        // The line would be:
        // "fun thisIsAVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryLongFunction(): AndAlsoALongReturnType {"
        // This exceeds 120 characters, so the newline should be allowed to remain
        functionReturnTypeSpacingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a function with return type on next line that would fit within max line length when put on same line then reformat`() {
        val code =
            """
            fun shortFunction():
                String {
                return "hello"
            }
            """.trimIndent()
        val formattedCode =
            """
            fun shortFunction(): String {
                return "hello"
            }
            """.trimIndent()
        // max_line_length is 120 by default in tests
        // "fun shortFunction(): String {" is well under 120 characters
        functionReturnTypeSpacingRuleAssertThat(code)
            .hasLintViolation(1, 20, "Single space expected between colon and return type")
            .isFormattedAs(formattedCode)
    }

    @Test
    fun `Given a parameterless function with return type on next line that would exceed max line length when put on same line then do not reformat`() {
        val code =
            """
            class Test {
                fun thisIsAVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryLongFunction():
                    AndAlsoALongReturnType {
                    return AndAlsoALongReturnType()
                }
            }
            """.trimIndent()
        // With indentation, this would definitely exceed 120 chars
        functionReturnTypeSpacingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a function with return type on same line that fits within max line length then do not reformat`() {
        val code =
            """
            fun thisIsAVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryLongFunction(): AndAlsoALongReturnType {
                return AndAlsoALongReturnType()
            }
            """.trimIndent()
        // Even though this exceeds max line length, the rule should not flag it
        // The max-line-length rule will handle this violation
        functionReturnTypeSpacingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a function with multiple spaces between colon and return type that would exceed max line length then reformat anyway`() {
        val code =
            """
            fun shortFunction():  String {
                return "hello"
            }
            """.trimIndent()
        val formattedCode =
            """
            fun shortFunction(): String {
                return "hello"
            }
            """.trimIndent()
        // Multiple spaces should be fixed regardless of line length
        functionReturnTypeSpacingRuleAssertThat(code)
            .hasLintViolation(1, 20, "Single space expected between colon and return type")
            .isFormattedAs(formattedCode)
    }

    @Test
    fun `Given a function with no space between colon and return type then reformat regardless of line length`() {
        val code =
            """
            fun thisIsAVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryLongFunction():AndAlsoALongReturnType {
                return AndAlsoALongReturnType()
            }
            """.trimIndent()
        val formattedCode =
            """
            fun thisIsAVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryLongFunction(): AndAlsoALongReturnType {
                return AndAlsoALongReturnType()
            }
            """.trimIndent()
        // Missing space should be fixed regardless of line length
        functionReturnTypeSpacingRuleAssertThat(code)
            .hasLintViolation(1, 91, "Single space expected between colon and return type")
            .isFormattedAs(formattedCode)
    }
}
